    // -----------------------------------------------------------------------
    // Authority-level terminal alignment witnesses
    //
    // Each test drives the TurnExecutionAuthority to a terminal phase and
    // verifies that classify_terminal matches the expected surface class.
    // -----------------------------------------------------------------------

    use crate::lifecycle::RunId;
    use crate::turn_execution_authority::{
        ContentShape, TurnExecutionAuthority, TurnExecutionInput, TurnExecutionMutator, TurnPhase,
    };
    use uuid::Uuid;

    fn test_run_id() -> RunId {
        RunId(Uuid::from_u128(1))
    }

    fn authority_at_calling_llm() -> TurnExecutionAuthority {
        let mut auth = TurnExecutionAuthority::new();
        auth.apply(TurnExecutionInput::StartConversationRun {
            run_id: test_run_id(),
        })
        .unwrap();
        auth.apply(TurnExecutionInput::PrimitiveApplied {
            run_id: test_run_id(),
            admitted_content_shape: ContentShape("text".into()),
            vision_enabled: false,
            image_tool_results_enabled: false,
        })
        .unwrap();
        auth
    }

    fn authority_at_draining_boundary() -> TurnExecutionAuthority {
        let mut auth = authority_at_calling_llm();
        auth.apply(TurnExecutionInput::LlmReturnedTerminal {
            run_id: test_run_id(),
        })
        .unwrap();
        assert_eq!(auth.phase(), TurnPhase::DrainingBoundary);
        auth
    }

    /// Witness: normal completion (LlmReturnedTerminal -> BoundaryComplete)
    /// classifies as Success.
    #[test]
    fn authority_normal_completion_classifies_success() {
        let mut auth = authority_at_draining_boundary();
        auth.apply(TurnExecutionInput::BoundaryComplete {
            run_id: test_run_id(),
        })
        .unwrap();
        assert_eq!(auth.phase(), TurnPhase::Completed);
        assert_eq!(
            classify_terminal(&auth.terminal_outcome()),
            Some(SurfaceResultClass::Success)
        );
    }

    /// Witness: budget exhaustion classifies as Success.
    #[test]
    fn authority_budget_exhaustion_classifies_success() {
        let mut auth = authority_at_calling_llm();
        auth.apply(TurnExecutionInput::BudgetExhausted {
            run_id: test_run_id(),
        })
        .unwrap();
        assert_eq!(auth.phase(), TurnPhase::Completed);
        assert_eq!(
            classify_terminal(&auth.terminal_outcome()),
            Some(SurfaceResultClass::Success)
        );
    }

    /// Witness: cancellation classifies as Cancelled.
    #[test]
    fn authority_cancellation_classifies_cancelled() {
        let mut auth = authority_at_calling_llm();
        auth.apply(TurnExecutionInput::CancelNow {
            run_id: test_run_id(),
        })
        .unwrap();
        assert_eq!(auth.phase(), TurnPhase::Cancelling);
        auth.apply(TurnExecutionInput::CancellationObserved {
            run_id: test_run_id(),
        })
        .unwrap();
        assert_eq!(auth.phase(), TurnPhase::Cancelled);
        assert_eq!(
            classify_terminal(&auth.terminal_outcome()),
            Some(SurfaceResultClass::Cancelled)
        );
    }

    /// Witness: extraction exhaustion (ExtractionExhausted -> Failed)
    /// classifies as HardFailure with RunFailed effect.
    #[test]
    fn authority_extraction_exhaustion_classifies_hard_failure() {
        let mut auth = authority_at_draining_boundary();
        // DrainingBoundary -> Extracting
        auth.apply(TurnExecutionInput::EnterExtraction {
            run_id: test_run_id(),
            max_retries: 0,
        })
        .unwrap();
        // Extracting -> Failed (retries exhausted immediately)
        let t = auth
            .apply(TurnExecutionInput::ExtractionExhausted {
                run_id: test_run_id(),
            })
            .unwrap();
        assert_eq!(auth.phase(), TurnPhase::Failed);
        assert!(t.effects.iter().any(|e| matches!(
            e,
            crate::turn_execution_authority::TurnExecutionEffect::RunFailed { .. }
        )));
        assert_eq!(
            classify_terminal(&auth.terminal_outcome()),
            Some(SurfaceResultClass::HardFailure)
        );
    }

